/**
Checksum algorithm for MSI_PLESSEY.

- `MOD_10`:
   Modulo 10.
- `MOD_11_IBM`:
   Modulo 11 IBM.
- `MOD_11_NCR`:
   Modulo 11 NCR.
- `MOD_10_10`:
   Modulo 1010.
- `MOD_11_10_IBM`:
   Modulo 1110 IBM.
- `MOD_11_10_NCR`:
   Modulo 1110 NCR.
*/
export type MsiPlesseyChecksumAlgorithm =
  | 'MOD_10'
  | 'MOD_11_IBM'
  | 'MOD_11_NCR'
  | 'MOD_10_10'
  | 'MOD_11_10_IBM'
  | 'MOD_11_10_NCR';

export const MsiPlesseyChecksumAlgorithmValues: MsiPlesseyChecksumAlgorithm[] = [
  'MOD_10',
  'MOD_11_IBM',
  'MOD_11_NCR',
  'MOD_10_10',
  'MOD_11_10_IBM',
  'MOD_11_10_NCR',
];

